import{H as e,V as t,et as n,j as r}from"./chunks/framework.C_EfTa_6.js";var i=JSON.parse(`{"title":"llama.cpp","description":"","frontmatter":{"title":"llama.cpp","order":34},"headers":[],"relativePath":"ai/app/engine/llama_cpp.md","filePath":"ai/app/engine/llama_cpp.md"}`),a={name:`ai/app/engine/llama_cpp.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="llama-cpp" tabindex="-1">llama.cpp <a class="header-anchor" href="#llama-cpp" aria-label="Permalink to “llama.cpp”">​</a></h1><p>llama.cpp 是 C++ 实现的轻量级 LLM 推理引擎，专为消费级硬件和边缘设备设计。它的设计哲学是&quot;在任何有 CPU 的设备上跑模型&quot;——GPU 是加速选项而非硬依赖。</p><h2 id="gguf-量化格式" tabindex="-1">GGUF 量化格式 <a class="header-anchor" href="#gguf-量化格式" aria-label="Permalink to “GGUF 量化格式”">​</a></h2><p>GGUF 是 llama.cpp 的原生模型格式。与 safetensors 不同，GGUF 将模型权重、tokenizer、超参数和元数据打包为单个文件，分发极其方便。支持从 2-bit 到 8-bit 的多种量化变体，K-quant 系列（Q4_K_M、Q5_K_M）通过重要性分析对不同层使用不同精度。</p><p>GGUF 的核心设计目标之一是支持 CPU+GPU 混合推理——<code>-ngl</code>（number of GPU layers）参数指定多少层放在 GPU 上，其余层走 CPU 内存。这突破了纯 GPU 推理的显存上限——如果系统有 128GB 内存和 24GB 显存，可以跑 70B 模型（模型加载在内存中，20-30 层放在 GPU 上加速）。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 全部层放 GPU</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./llama-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> model-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ngl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 999</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 部分层放 GPU，其余走 CPU</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./llama-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> model-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ngl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ctx-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4096</span></span></code></pre></div><h2 id="硬件后端" tabindex="-1">硬件后端 <a class="header-anchor" href="#硬件后端" aria-label="Permalink to “硬件后端”">​</a></h2><p>llama.cpp 支持多种 GPU 后端，编译时选择：</p><ul><li><strong>CUDA</strong>：NVIDIA GPU，通过 cuBLAS 加速。编译选项 <code>-DGGML_CUDA=ON</code></li><li><strong>Metal</strong>：Apple Silicon（M1/M2/M3），GPU 推理。编译选项 <code>-DGGML_METAL=ON</code></li><li><strong>ROCm/HIP</strong>：AMD GPU，编译选项 <code>-DGGML_HIPBLAS=ON</code>。RDNA 3 上的 GGUF 推理稳定性与 CUDA 几乎无异</li><li><strong>Vulkan</strong>：跨平台 GPU 后端，支持 NVIDIA/AMD/Intel</li><li><strong>CPU</strong>：纯 CPU 推理，通过 BLAS 库加速（OpenBLAS、Intel MKL）</li></ul><p>Apple Silicon 上的 Metal 后端表现优异——M1 Max 32 核 GPU 上 7B 模型 Q4_K_M 推理速度约 20-30 token/s。</p><h2 id="推理加速" tabindex="-1">推理加速 <a class="header-anchor" href="#推理加速" aria-label="Permalink to “推理加速”">​</a></h2><p>llama.cpp 集成了投机解码——通过 <code>--draft-model</code> 指定同系列的微型模型做 draft：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./llama-server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen3.6-32b-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --draft-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen3.6-1.8b-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --speculative-tokens</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ngl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 999</span></span></code></pre></div><p>KV Cache 量化通过 <code>--cache-type-k</code> 和 <code>--cache-type-v</code> 控制，支持 INT8 和 INT4：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># KV Cache INT8 量化（32K 上下文场景显著节省显存）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./llama-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> model.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ctx-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 32768</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --cache-type-k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> q8_0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cache-type-v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> q8_0</span></span></code></pre></div><p>Flash Attention 在编译时启用（<code>-DGGML_CUDA_FA=ON</code>），对长上下文推理有明显加速。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to “使用方式”">​</a></h2><p>llama.cpp 提供多种交互方式：</p><p><code>llama-cli</code>：命令行交互式对话，适合快速测试 <code>llama-server</code>：HTTP 服务，兼容 OpenAI API（<code>/v1/chat/completions</code>），适合集成到应用 <code>llama-perplexity</code>：计算模型在测试集上的困惑度，评估量化质量 <code>llama-bench</code>：基准测试工具，测试不同量化格式和硬件的推理速度</p><p>C++ API 可直接嵌入应用，Python 绑定通过 <code>llama-cpp-python</code> 提供。Rust 绑定 <code>llama-cpp-rs</code> 提供安全的 FFI 封装。</p><h2 id="与-ollama-的关系" tabindex="-1">与 Ollama 的关系 <a class="header-anchor" href="#与-ollama-的关系" aria-label="Permalink to “与 Ollama 的关系”">​</a></h2><p>Ollama 是 llama.cpp 的上层封装。它自动管理 GGUF 版本选择、GPU 层数配置、模型下载和更新。Ollama 适合&quot;不想管底层细节&quot;的用户，llama.cpp 适合需要精细控制硬件参数的场景。两者使用相同的 GGUF 模型文件，可以在 Ollama 和 llama.cpp 之间切换。</p><p>Ollama 不支持连续批处理（每个请求串行处理），不适合高并发 API 服务。对于这类需求，应使用 vLLM 或 SGLang。</p>`,23)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};